components.css:
.ds-btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: 40px;
  padding: 8px 20px;
  background-color: #d4a843;
  color: #1a1a18;
  border: none;
  border-radius: 4px;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.4;
  letter-spacing: 0.02em;
  cursor: pointer;
  transition: background-color 200ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-primary:hover {
  background-color: #b8922e;
}
.ds-btn-primary:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--color-background), 0 0 0 4px #d4a843;
}
.ds-btn-primary:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Dark mode */
.dark .ds-btn-primary {
  background-color: #e8c55a;
  color: #141412;
}
.dark .ds-btn-primary:hover {
  background-color: #d4b44a;
}

.ds-btn-outline {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: 40px;
  padding: 8px 20px;
  background-color: transparent;
  color: #1a1a18;
  border: 1px solid #e5e5e0;
  border-radius: 4px;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.4;
  letter-spacing: 0.02em;
  cursor: pointer;
  transition: background-color 200ms cubic-bezier(0.4, 0, 0.2, 1), color 200ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-outline:hover {
  background-color: #fafaf8;
}
.ds-btn-outline:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--color-background), 0 0 0 4px #d4a843;
}

/* Dark mode */
.dark .ds-btn-outline {
  border-color: #2e2e2c;
  color: #ecece8;
}
.dark .ds-btn-outline:hover {
  background-color: #1e1e1c;
}

.ds-btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: 40px;
  padding: 8px 12px;
  background-color: transparent;
  color: #1a1a18;
  border: none;
  border-radius: 4px;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.4;
  letter-spacing: 0.02em;
  cursor: pointer;
  transition: background-color 200ms cubic-bezier(0.4, 0, 0.2, 1), color 200ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-ghost:hover {
  background-color: #fafaf8;
}
.ds-btn-ghost:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--color-background), 0 0 0 4px #d4a843;
}

/* Destructive variant */
.ds-btn-ghost-destructive {
  color: #c0392b;
}
.ds-btn-ghost-destructive:hover {
  background-color: #fef2f2;
}

/* Dark mode */
.dark .ds-btn-ghost:hover {
  background-color: #1e1e1c;
}
.dark .ds-btn-ghost-destructive {
  color: #ef4444;
}
.dark .ds-btn-ghost-destructive:hover {
  background-color: rgba(239, 68, 68, 0.1);
}

.ds-card {
  background-color: #ffffff;
  color: #1a1a18;
  border: 1px solid #e5e5e0;
  border-radius: 12px;
  padding: 24px;
  transition: border-color 200ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-card:hover {
  border-color: #d4a843;
}
.ds-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
}
.ds-card-title {
  font-size: 0.875rem;
  font-weight: 600;
  line-height: 1.3;
  color: #403f3a;
}
.ds-card-content {
  padding-top: 0;
}
.ds-card-value {
  font-size: 1.5rem;
  font-weight: 700;
  line-height: 1.2;
  color: #1a1a18;
}

/* Dark mode */
.dark .ds-card {
  background-color: #1e1e1c;
  border-color: #2e2e2c;
  color: #ecece8;
}
.dark .ds-card:hover {
  border-color: #e8c55a;
}
.dark .ds-card-title {
  color: #a0a09a;
}
.dark .ds-card-value {
  color: #ecece8;
}

.ds-input {
  display: flex;
  height: 40px;
  width: 100%;
  padding: 8px 12px;
  background-color: #fafaf8;
  color: #1a1a18;
  border: 1px solid #e5e5e0;
  border-radius: 8px;
  font-size: 0.875rem;
  line-height: 1.6;
  transition: border-color 200ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 200ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-input::placeholder {
  color: #403f3a;
  opacity: 1;
}
.ds-input:focus {
  outline: none;
  border-color: #d4a843;
  box-shadow: 0 0 0 2px var(--color-background), 0 0 0 4px rgba(212, 168, 67, 0.3);
}
.ds-input:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Dark mode */
.dark .ds-input {
  background-color: #141412;
  color: #ecece8;
  border-color: #2e2e2c;
}
.dark .ds-input::placeholder {
  color: #8a8a85;
}
.dark .ds-input:focus {
  border-color: #e8c55a;
  box-shadow: 0 0 0 2px #141412, 0 0 0 4px rgba(232, 197, 90, 0.3);
}

.ds-table {
  overflow-x: auto;
  border: 1px solid #e5e5e0;
  border-radius: 12px;
}
.ds-table table {
  width: 100%;
  border-collapse: collapse;
}
.ds-table-th {
  padding: 12px 16px;
  text-align: left;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.02em;
  color: #403f3a;
  background-color: rgba(0, 0, 0, 0.02);
  border-bottom: 1px solid #e5e5e0;
}
.ds-table-td {
  padding: 12px 16px;
  font-size: 0.875rem;
  line-height: 1.6;
  color: #1a1a18;
  border-bottom: 1px solid #e5e5e0;
}
.ds-table-td:last-child {
  border-bottom: none;
}
.ds-table tr:last-child .ds-table-td {
  border-bottom: none;
}
.ds-table tr:hover .ds-table-td {
  background-color: rgba(0, 0, 0, 0.01);
}
.ds-table-num {
  font-family: ui-monospace, SFMono-Regular, monospace;
  text-align: right;
}
.ds-table-positive {
  color: #2a6b4a;
}
.ds-table-negative {
  color: #c0392b;
}

/* Dark mode */
.dark .ds-table {
  border-color: #2e2e2c;
}
.dark .ds-table-th {
  color: #a0a09a;
  background-color: rgba(255, 255, 255, 0.02);
  border-bottom-color: #2e2e2c;
}
.dark .ds-table-td {
  color: #ecece8;
  border-bottom-color: #2e2e2c;
}
.dark .ds-table tr:hover .ds-table-td {
  background-color: rgba(255, 255, 255, 0.02);
}
.dark .ds-table-positive {
  color: #22c55e;
}
.dark .ds-table-negative {
  color: #ef4444;
}

.ds-dialog-overlay {
  display: flex;
  align-items: center;
  justify-content: center;
  position: fixed;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.4);
  z-index: 100;
}
.ds-dialog {
  width: min(480px, calc(100vw - 32px));
  background-color: #ffffff;
  border: 1px solid #e5e5e0;
  border-radius: 16px;
  padding: 24px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.08);
}
.ds-dialog-header {
  margin-bottom: 20px;
}
.ds-dialog-title {
  font-size: 1.25rem;
  font-weight: 600;
  line-height: 1.3;
  color: #1a1a18;
  margin: 0 0 4px;
}
.ds-dialog-description {
  font-size: 0.875rem;
  color: #73726d;
  margin: 0;
}
.ds-dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 16px;
}

/* Dark mode */
.dark .ds-dialog {
  background-color: #1e1e1c;
  border-color: #2e2e2c;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.3);
}
.dark .ds-dialog-title {
  color: #ecece8;
}
.dark .ds-dialog-description {
  color: #8a8a85;
}
